// 7/7 send window tussen 08:00 en 21:00 Europe/Brussels (alle dagen incl.
// weekend en feestdagen). Geen dag-van-de-week restrictie.
//
// Uur-venster (08-21) is bewust breed maar NIET 24/7: sends om 03:00 's
// nachts zijn een klassiek bot/bulk signal dat classifiers triggeren. Binnen
// 13u/dag window × ticks-elke-5min = 156 ticks/dag, ruim genoeg voor cap
// tot 100/dag.
//
// DST wordt automatisch afgehandeld via Europe/Brussels timezone.
const now = new Date();
const parts = new Intl.DateTimeFormat('nl-BE', {
  timeZone: 'Europe/Brussels',
  weekday: 'short',
  hour: '2-digit',
  hour12: false,
}).formatToParts(now);

const dow = parts.find(p => p.type === 'weekday')?.value ?? '';
const hour = parseInt(parts.find(p => p.type === 'hour')?.value ?? '0', 10);

const inWindow = hour >= 8 && hour < 21;

if (!inWindow) {
  return [];  // buiten 08-21, skip tick
}
return [{ json: { weekday: dow, hour, ok: true } }];

// Optional: log voor debug / cost summary
const data = $input.first().json;
return [{ json: { ts: new Date().toISOString(), messageId: data.messageId, draftId: data.draftId, businessId: data.businessId, sentToday: data.sentToday, maxToday: data.maxToday } }];
